// ============================================================
// Redaction utilities
// ============================================================
object Redactor {

    // Keys whose values must NEVER appear in logs
    private val SENSITIVE_KEYS = setOf(
        "password", "passwd", "secret", "token", "access_token",
        "refresh_token", "authorization", "cookie", "set-cookie",
        "x-api-key", "api_key", "apikey", "credit_card", "creditcard",
        "card_number", "cvv", "ssn", "social_security",
        "pin", "otp", "mfa_code", "private_key", "client_secret"
    )

    // Patterns that look like bearer tokens, JWTs, long hex strings
    private val TOKEN_PATTERNS = listOf(
        Regex("Bearer\\s+[A-Za-z0-9\\-._~+/]+=*", RegexOption.IGNORE_CASE),
        Regex("eyJ[A-Za-z0-9\\-_]+\\.eyJ[A-Za-z0-9\\-_]+\\.[A-Za-z0-9\\-_.+/=]+"),
        Regex("[0-9a-fA-F]{32,}")
    )

    /**
     * Redact a single string value that is known to be sensitive.
     * Shows first 2 and last 2 characters for correlation, rest replaced.
     */
    fun redactValue(value: String): String {
        if (value.length <= 6) return "***REDACTED***"
        return "${value.take(2)}***REDACTED***${value.takeLast(2)}"
    }

    /**
     * Determine whether a key name is sensitive (case-insensitive).
     */
    fun isSensitiveKey(key: String): Boolean {
        val lower = key.lowercase().replace("-", "_").replace(" ", "_")
        return SENSITIVE_KEYS.any { lower.contains(it) }
    }

    /**
     * Redact sensitive key-value pairs in a Map.
     */
    fun redactMap(map: Map<String, Any?>): Map<String, Any?> {
        return map.mapValues { (key, value) ->
            when {
                isSensitiveKey(key) -> "***REDACTED***"
                value is String -> redactInlineTokens(value)
                value is Map<*, *> -> {
                    @Suppress("UNCHECKED_CAST")
                    redactMap(value as Map<String, Any?>)
                }
                else -> value
            }
        }
    }

    /**
     * Redact headers specifically – returns a new map with sensitive headers masked.
     */
    fun redactHeaders(headers: Map<String, String>): Map<String, String> {
        return headers.mapValues { (key, value) ->
            if (isSensitiveKey(key)) "***REDACTED***"
            else redactInlineTokens(value)
        }
    }

    /**
     * Scan a free-form string for inline tokens / secrets and mask them.
     */
    fun redactInlineTokens(text: String): String {
        var result = text
        for (pattern in TOKEN_PATTERNS) {
            result = pattern.replace(result) { matchResult ->
                redactValue(matchResult.value)
            }
        }
        return result
    }

    /**
     * Redact a JSON-like body string.  For production we truncate and
     * strip known sensitive fields via simple regex (avoids pulling in
     * a JSON library just for logging).
     */
    fun redactBody(body: String?, maxLength: Int = 1024): String {
        if (body.isNullOrBlank()) return "[empty]"

        var sanitized = body

        // Replace values of sensitive JSON keys: "password":"anything"
        for (key in SENSITIVE_KEYS) {
            val regex = Regex(
                """("$key"\s*:\s*)"[^"]*"""",
                RegexOption.IGNORE_CASE
            )
            sanitized = regex.replace(sanitized!!) { match ->
                "${match.groupValues[1]}\"***REDACTED***\""
            }
        }

        sanitized = redactInlineTokens(sanitized!!)

        if (sanitized.length > maxLength) {
            sanitized = sanitized.take(maxLength) + "...[TRUNCATED, total=${body.length}]"
        }

        return sanitized
    }

    /**
     * Produce a safe summary of an exception for production logs.
     * Full stack traces are only emitted in debug builds.
     */
    fun safeExceptionSummary(throwable: Throwable, includeFullTrace: Boolean = false): String {
        val sb = StringBuilder()
        sb.appendLine("Exception: ${throwable.javaClass.simpleName}")
        // Message may contain sensitive data – redact inline tokens
        val msg = throwable.message?.let { redactInlineTokens(it) } ?: "no message"
        sb.appendLine("Message: $msg")

        if (includeFullTrace) {
            val sw = StringWriter()
            throwable.printStackTrace(PrintWriter(sw))
            // Redact any tokens that might appear in the trace
            sb.appendLine("StackTrace:\n${redactInlineTokens(sw.toString())}")
        } else {
            // Only top 3 frames
            throwable.stackTrace.take(3).forEach { frame ->
                sb.appendLine("  at $frame")
            }
            sb.appendLine("  ... (${(throwable.stackTrace.size - 3).coerceAtLeast(0)} more frames)")
        }

        throwable.cause?.let {
            sb.appendLine("Caused by: ${it.javaClass.simpleName}: ${it.message?.let { m -> redactInlineTokens(m) }}")
        }

        return sb.toString()
    }
}

// ============================================================
// Secure file-based log writer (for on-device diagnostics)
// ============================================================
class SecureFileLogger(context: Context) {

    private val logDir = File(context.filesDir, "secure_logs").also { it.mkdirs() }
    private val dateFormat = SimpleDateFormat("yyyy-MM-dd", Locale.US)
    private val timestampFormat = SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSSZ", Locale.US)
    private val executor = Executors.newSingleThreadExecutor()
    private val buffer = ConcurrentLinkedQueue<String>()
    private val maxFileSize = 2 * 1024 * 1024L  // 2 MB per file
    private val maxFiles = 5

    fun write(level: String, tag: String, message: String) {
        val timestamp = timestampFormat.format(Date())
        val line = "$timestamp [$level/$tag] $message"
        buffer.add(line)
        executor.submit { flush() }
    }

    private fun flush() {
        val file = File(logDir, "log_${dateFormat.format(Date())}.txt")
        try {
            // Rotate if needed
            if (file.exists() && file.length() > maxFileSize) {
                rotateFiles()
            }
            FileWriter(file, true).use { writer ->
                while (buffer.isNotEmpty()) {
                    val entry = buffer.poll() ?: break
                    writer.appendLine(entry)
                }
            }
        } catch (e: Exception) {
            // Logging failure must not crash the app
            Log.e("SecureFileLogger", "Failed to write log", e)
        }
    }

    private fun rotateFiles() {
        val files = logDir.listFiles()?.sortedBy { it.lastModified() } ?: return
        while (files.size >= maxFiles) {
            files.firstOrNull()?.delete()
        }
    }

    /**
     * Retrieve recent logs for a crash report upload.
     * Caller is responsible for encrypting before transmission.
     */
    fun getRecentLogs(maxLines: Int = 500): List<String> {
        val allLines = mutableListOf<String>()
        logDir.listFiles()
            ?.sortedByDescending { it.lastModified() }
            ?.forEach { file ->
                if (allLines.size >= maxLines) return@forEach
                file.readLines().takeLast(maxLines - allLines.size).let {
                    allLines.addAll(0, it)
                }
            }
        return allLines.takeLast(maxLines)
    }

    fun clearLogs() {
        logDir.listFiles()?.forEach { it.delete() }
    }
}

// ============================================================
// Custom Timber trees
// ============================================================

/**
 * Debug tree – used only in DEBUG builds.
 * Allows verbose output including full stack traces.
 */
class DebugLogTree : Timber.DebugTree() {
    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        // Even in debug, redact obvious secrets
        val safeMessage = Redactor.redactInlineTokens(message)
        super.log(priority, tag, safeMessage, t)
    }

    override fun createStackElementTag(element: StackTraceElement): String {
        return "(${element.fileName}:${element.lineNumber})#${element.methodName}"
    }
}

/**
 * Production tree – writes WARN+ to logcat and to encrypted file.
 * Never emits DEBUG or VERBOSE in production.
 */
class ProductionLogTree(private val fileLogger: SecureFileLogger) : Timber.Tree() {

    override fun isLoggable(tag: String?, priority: Int): Boolean {
        // In production only WARN, ERROR, WTF
        return priority >= Log.WARN
    }

    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        val safeMessage = Redactor.redactInlineTokens(message)
        val levelName = when (priority) {
            Log.WARN -> "W"
            Log.ERROR -> "E"
            Log.ASSERT -> "WTF"
            else -> "I"
        }

        // Write to secure file
        val fullMessage = if (t != null) {
            "$safeMessage\n${Redactor.safeExceptionSummary(t, includeFullTrace = false)}"
        } else {
            safeMessage
        }
        fileLogger.write(levelName, tag ?: "App", fullMessage)

        // Also send to logcat (production builds should use ProGuard to strip)
        Log.println(priority, tag, safeMessage)
    }
}

