/**
 * Logs authentication events with appropriate redaction.
 */
object AuthLogger {

    fun logLoginAttempt(username: String, method: String) {
        // Never log the password. Partially redact username (could be email).
        val safeUser = if (username.contains("@")) {
            val parts = username.split("@")
            "${parts[0].take(2)}***@${parts.getOrElse(1) { "***" }}"
        } else {
            Redactor.redactValue(username)
        }
        Timber.tag("AUTH").i("Login attempt | user=%s | method=%s", safeUser, method)
    }

    fun logLoginSuccess(userId: String, method: String) {
        Timber.tag("AUTH").i(
            "Login SUCCESS | userId=%s | method=%s",
            Redactor.redactValue(userId),
            method
        )
    }

    fun logLoginFailure(username: String, reason: String, exception: Throwable? = null) {
        val safeUser = if (username.contains("@")) {
            val parts = username.split("@")
            "${parts[0].take(2)}***@${parts.getOrElse(1) { "***" }}"
        } else {
            Redactor.redactValue(username)
        }
        val safeReason = Redactor.redactInlineTokens(reason)

        if (exception != null) {
            Timber.tag("AUTH").w(
                "Login FAILED | user=%s | reason=%s | error=%s",
                safeUser,
                safeReason,
                Redactor.safeExceptionSummary(exception, includeFullTrace = AppBuildConfig.DEBUG)
            )
        } else {
            Timber.tag("AUTH").w("Login FAILED | user=%s | reason=%s", safeUser, safeReason)
        }
    }

    fun logTokenRefresh(success: Boolean, errorMessage: String? = null) {
        if (success) {
            Timber.tag("AUTH").i("Token refresh SUCCESS")
        } else {
            Timber.tag("AUTH").w(
                "Token refresh FAILED | error=%s",
                errorMessage?.let { Redactor.redactInlineTokens(it) } ?: "unknown"
            )
        }
    }

    fun logLogout(userId: String, reason: String) {
        Timber.tag("AUTH").i(
            "Logout | userId=%s | reason=%s",
            Redactor.redactValue(userId),
            reason
        )
    }
}

/**
 * Logs database operations with parameter redaction.
 */
object DatabaseLogger {

    /**
     * Log a query. Parameters that look sensitive are redacted.
     *
     * @param query       The SQL or query description (table/operation).
     *                    In production we log only the operation type, not raw SQL.
     * @param params      Named parameters.
     * @param durationMs  Execution time.
     */
    fun logQuery(
        operation: String,
        table: String,
        params: Map<String, Any?> = emptyMap(),
        durationMs: Long = -1,
        rowCount: Int? = null
    ) {
        val safeParams = Redactor.redactMap(params)
        val duration = if (durationMs >= 0) "${durationMs}ms" else "n/a"
        val rows = rowCount?.toString() ?: "n/a"

        if (AppBuildConfig.DEBUG) {
            Timber.tag("DB").d(
                "%s on [%s] | params=%s | duration=%s | rows=%s",
                operation, table, safeParams, duration, rows
            )
        } else {
            // Production: minimal info, no params
            Timber.tag("DB").i(
                "%s on [%s] | duration=%s | rows=%s",
                operation, table, duration, rows
            )
        }
    }

    fun logSlowQuery(
        operation: String,
        table: String,
        durationMs: Long,
        thresholdMs: Long = 500
    ) {
        if (durationMs > thresholdMs) {
            Timber.tag("DB").w(
                "SLOW QUERY | %s on [%s] | duration=%dms (threshold=%dms)",
                operation, table, durationMs, thresholdMs
            )
        }
    }

    fun logQueryError(
        operation: String,
        table: String,
        exception: Throwable
    ) {
        Timber.tag("DB").e(
            "Query ERROR | %s on [%s] | %s",
            operation, table,
            Redactor.safeExceptionSummary(exception, includeFullTrace = AppBuildConfig.DEBUG)
        )
    }

    fun logMigration(fromVersion: Int, toVersion: Int, success: Boolean, durationMs: Long) {
        if (success) {
            Timber.tag("DB").i(
                "Migration SUCCESS | v%d -> v%d | duration=%dms",
                fromVersion, toVersion, durationMs
            )
        } else {
            Timber.tag("DB").e(
                "Migration FAILED | v%d -> v%d | duration=%dms",
                fromVersion, toVersion, durationMs
            )
        }
    }
}

/**
 * Logs API / network requests and responses with full redaction.
 */
object ApiLogger {

    data class RequestLog(
        val method: String,
        val url: String,
        val headers: Map<String, String> = emptyMap(),
        val body: String? = null,
        val requestId: String? = null
    )

    data class ResponseLog(
        val statusCode: Int,
        val url: String,
        val headers: Map<String, String> = emptyMap(),
        val body: String? = null,
        val durationMs: Long = -1,
        val requestId: String? = null
    )

    fun logRequest(request: RequestLog) {
        val safeHeaders = Redactor.redactHeaders(request.headers)
        val safeUrl = redactUrlParams(request.url)

        if (AppBuildConfig.DEBUG) {
            val safeBody = Redactor.redactBody(request.body, maxLength = 2048)
            Timber.tag("API").d(
                "--> %s %s | id=%s\nHeaders: %s\nBody: %s",
                request.method,
                safeUrl,
                request.requestId ?: "n/a",
                safeHeaders,
                safeBody
            )
        } else {
            // Production: method, path, request id only
            Timber.tag("API").i(
                "--> %s %s | id=%s",
                request.method,
                safeUrl,
                request.requestId ?: "n/a"
            )
        }
    }

    fun logResponse(response: ResponseLog) {
        val safeUrl = redactUrlParams(response.url)
        val duration = if (response.durationMs >= 0) "${response.durationMs}ms" else "n/a"

        if (AppBuildConfig.DEBUG) {
            val safeHeaders = Redactor.redactHeaders(response.headers)
            val safeBody = Redactor.redactBody(response.body, maxLength = 2048)
            Timber.tag("API").d(
                "<-- %d %s | id=%s | duration=%s\nHeaders: %s\nBody: %s",
                response.statusCode,
                safeUrl,
                response.requestId ?: "n/a",
                duration,
                safeHeaders,
                safeBody
            )
        } else {
            val level = when {
                response.statusCode in 200..299 -> Log.INFO
                response.statusCode in 400..499 -> Log.WARN
                else -> Log.ERROR
            }
            val msg = String.format(
                "<-- %d %s | id=%s | duration=%s",
                response.statusCode,
                safeUrl,
                response.requestId ?: "n/a",
                duration
            )
            Timber.tag("API").log(level, msg)
        }
    }

    fun logApiError(
        method: String,
        url: String,
        exception: Throwable,
        requestId: String? = null
    ) {
        val safeUrl = redactUrlParams(url)
        Timber.tag("API").e(
            "API ERROR | %s %s | id=%s | %s",
            method,
            safeUrl,
            requestId ?: "n/a",
            Redactor.safeExceptionSummary(exception, includeFullTrace = AppBuildConfig.DEBUG)
        )
    }

    /**
     * Redact sensitive query parameters in URLs (token, key, secret, etc.)
     */
    private fun redactUrlParams(url: String): String {
        if (!url.contains("?")) return url
        val parts = url.split("?", limit = 2)
        val basePath = parts[0]
        val queryString = parts.getOrElse(1) { return url }

        val redactedParams = queryString.split("&").joinToString("&") { param ->
            val kv = param.split("=", limit = 2)
            if (kv.size == 2 && Redactor.isSensitiveKey(kv[0])) {
                "${kv[0]}=***REDACTED***"
            } else {
                param
            }
        }
        return "$basePath?$redactedParams"
    }
}

/**
 * Centralized exception logger.
 */
object ExceptionLogger {

    /**
     * Log a caught exception. In debug builds the full trace is emitted;
     * in production only a safe summary is logged.
     */
    fun logException(
        tag: String = "EXCEPTION",
        message: String,
        throwable: Throwable,
        extras: Map<String, Any?> = emptyMap()
    ) {
        val safeMessage = Redactor.redactInlineTokens(message)
        val safeExtras = if (extras.isNotEmpty()) Redactor.redactMap(extras).toString() else ""
        val summary = Redactor.safeExceptionSummary(
            throwable,
            includeFullTrace = AppBuildConfig.DEBUG
        )

        Timber.tag(tag).e(
            "%s | %s%s",
            safeMessage,
            summary,
            if (safeExtras.isNotEmpty()) " | extras=$safeExtras" else ""
        )
    }

    /**
     * Log a fatal / unrecoverable error.
     */
    fun logFatal(
        message: String,
        throwable: Throwable,
        extras: Map<String, Any?> = emptyMap()
    ) {
        logException("FATAL", message, throwable, extras)
    }
}

// ============================================================
// Initialization – call from Application.onCreate()
// ============================================================
object AppLogger {

    private var fileLogger: SecureFileLogger? = null

    /**
     * Initialize the logging system.
     *
     * @param context  Application context.
     * @param isDebug  Typically BuildConfig.DEBUG.
     */
    fun init(context: Context, isDebug: Boolean) {
        AppBuildConfig.DEBUG = isDebug

        // Uproot any existing trees to avoid duplicates on re-init
        Timber.uprootAll()

        if (isDebug) {
            AppBuildConfig.LOG_LEVEL = Log.VERBOSE
            Timber.plant(DebugLogTree())
            Timber.tag("AppLogger").d("Debug logging initialized")
        } else {
            AppBuildConfig.LOG_LEVEL = Log.WARN
            val secureLogger = SecureFileLogger(context)
            fileLogger = secureLogger
            Timber.plant(ProductionLogTree(secureLogger))
            Timber.tag("AppLogger").i("Production logging initialized")
        }

        // Install a global uncaught exception handler that logs before crashing
        val defaultHandler = Thread.getDefaultUncaughtExceptionHandler()
        Thread.setDefaultUncaughtExceptionHandler { thread, throwable ->
            ExceptionLogger.logFatal(
                "Uncaught exception on thread ${thread.name}",
                throwable
            )
            // Delegate to the default handler (crash reporting SDK, system, etc.)
            defaultHandler?.uncaughtException(thread, throwable)
        }
    }

    /**
     * Retrieve on-device logs for a diagnostic report.
     */
    fun getRecentLogs(maxLines: Int = 500): List<String> {
        return fileLogger?.getRecentLogs(maxLines) ?: emptyList()
    }

    /**
     * Clear on-device logs (e.g., after successful upload).
     */
    fun clearLogs() {
        fileLogger?.clearLogs()
    }
}

