// ============================================================
// Usage examples (would live in your actual app code)
// ============================================================
object LoggingUsageExamples {

    fun demonstrateAuthLogging() {
        // Login attempt
        AuthLogger.logLoginAttempt(
            username = "user@example.com",
            method = "email_password"
        )

        // Successful login
        AuthLogger.logLoginSuccess(
            userId = "usr_abc123def456",
            method = "email_password"
        )

        // Failed login
        AuthLogger.logLoginFailure(
            username = "user@example.com",
            reason = "Invalid credentials",
            exception = IllegalArgumentException("Authentication failed for provided credentials")
        )

        // Token refresh
        AuthLogger.logTokenRefresh(success = true)
        AuthLogger.logTokenRefresh(success = false, errorMessage = "Token expired, refresh_token=eyJhbGciOiJIUzI1NiJ9.invalid")

        // Logout
        AuthLogger.logLogout(userId = "usr_abc123def456", reason = "user_initiated")
    }

    fun demonstrateDatabaseLogging() {
        // Normal query
        DatabaseLogger.logQuery(
            operation = "SELECT",
            table = "users",
            params = mapOf("email" to "user@example.com", "password" to "supersecret123"),
            durationMs = 12,
            rowCount = 1
        )

        // Slow query warning
        DatabaseLogger.logSlowQuery(
            operation = "SELECT",
            table = "orders",
            durationMs = 1200,
            thresholdMs = 500
        )

        // Query error
        DatabaseLogger.logQueryError(
            operation = "INSERT",
            table = "sessions",
            exception = RuntimeException("UNIQUE constraint failed: sessions.token")
        )

        // Migration
        DatabaseLogger.logMigration(fromVersion = 3, toVersion = 4, success = true, durationMs = 450)
    }

    fun demonstrateApiLogging() {
        // Request
        ApiLogger.logRequest(
            ApiLogger.RequestLog(
                method = "POST",
                url = "https://api.example.com/v1/login?api_key=sk_live_abc123",
                headers = mapOf(
                    "Content-Type" to "application/json",
                    "Authorization" to "Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJzdWIiOiIxMjM0NTY3ODkwIn0.dozjgNryP4J3jVmNHl0w5N_XgL0n3I9PlFUP0THsR8U",
                    "X-Request-ID" to "req_12345"
                ),
                body = """{"email":"user@example.com","password":"MyS3cretP@ss!","remember":true}""",
                requestId = "req_12345"
            )
        )

        // Response
        ApiLogger.logResponse(
            ApiLogger.ResponseLog(
                statusCode = 200,
                url = "https://api.example.com/v1/login",
                headers = mapOf(
                    "Content-Type" to "application/json",
                    "Set-Cookie" to "session=abc123secret; HttpOnly; Secure"
                ),
                body = """{"user_id":"usr_123","access_token":"eyJhbGciOiJIUzI1NiJ9.newtoken.sig","name":"John"}""",
                durationMs = 234,
                requestId = "req_12345"
            )
        )

        // API error
        ApiLogger.logApiError(
            method = "GET",
            url = "https://api.example.com/v1/profile?token=secret_token_value",
            exception = java.net.SocketTimeoutException("Connect timed out after 30000ms"),
            requestId = "req_67890"
        )
    }

    fun demonstrateExceptionLogging() {
        try {
            throw RuntimeException(
                "Failed to decrypt payload with key=abcdef1234567890abcdef1234567890",
                IllegalStateException("Invalid AES key length")
            )
        } catch (e: Exception) {
            ExceptionLogger.logException(
                tag = "CRYPTO",
                message = "Decryption failed for user session",
                throwable = e,
                extras = mapOf(
                    "userId" to "usr_abc123",
                    "sessionToken" to "eyJhbGciOiJIUzI1NiJ9.session.data",
                    "algorithm" to "AES-256-GCM"
                )
            )
        }
    }
}